"""
Prompt sampling for OpenEvolve (Bootcamp-style).
- Reduce noisy/verbose text in evolution_history.
- Make prompt rendering safe with str.format (escape braces in inserted text).
- Optionally keep state JSON minimal to avoid messy/too-long prompts.
本版本新增（核心诉求）：
- 对所有用于 prompt 展示的 program（top/diverse/inspirations/previous_programs 等）：
  统一优先使用 program.metadata.gene（或 program.code 里的 _gene/gene）来替代 program.code 的展示内容。
  即：prompt 里看到的是 gene 轨迹，而不是单次 variables dict。
- 对 current_program / parent_program（state json 字符串）：
  若包含 gene 字段，则在简化显示时优先显示 gene 的摘要（turn 数、最后一轮参数示例）。
- initial_program 保持原样（不会强行注入 gene；若初始 JSON 自己没有 gene，就不会显示 gene）。
"""
import logging
import random
import json
import os
import sys
import time
import hashlib
from typing import Any, Dict, List, Optional, Union
from openevolve.config import PromptConfig
from openevolve.prompt.templates import TemplateManager
from openevolve.utils.metrics_utils import (
    get_fitness_score,
    format_feature_coordinates,
)
logger = logging.getLogger(__name__)
_DUMPED_ONCE_BY_PID = set()

class PromptSampler:
    """Generates prompts for code evolution"""
    def __init__(self, config: PromptConfig):
        self.config = config
        self.template_manager = TemplateManager(custom_template_dir=config.template_dir)
        self.system_template_override = None
        self.user_template_override = None
        if not hasattr(logger, "_prompt_sampler_logged"):
            logger.info("Initialized prompt sampler")
            logger._prompt_sampler_logged = True
    def set_templates(
        self,
        system_template: Optional[str] = None,
        user_template: Optional[str] = None
    ) -> None:
        self.system_template_override = system_template
        self.user_template_override = user_template
        logger.info(f"Set custom templates: system={system_template}, user={user_template}")
    # ----------------------------- JSON helpers -----------------------------
    def _try_load_json(self, text: str) -> Optional[Any]:
        if not isinstance(text, str):
            return None
        s = text.strip()
        if not s:
            return None
        if not (s.startswith("{") or s.startswith("[")):
            return None
        try:
            return json.loads(s)
        except Exception:
            return None
    def _pretty_json(self, text: str) -> str:
        obj = self._try_load_json(text)
        if obj is None:
            return text
        try:
            return json.dumps(obj, ensure_ascii=False, indent=2)
        except Exception:
            return text
    def _escape_braces_for_format(self, s: str) -> str:
        """
        Escape literal braces so Python str.format won't treat them as placeholders.
        REQUIRED if we inject JSON/code containing '{' '}' into a format-template.
        """
        if not isinstance(s, str) or not s:
            return s
        return s.replace("{", "{{").replace("}", "}}")
    # ----------------------------- gene helpers -----------------------------
    def _extract_gene_from_program_dict(self, program: Dict[str, Any]) -> Optional[List[Dict[str, Any]]]:
        """
        从 Program.to_dict() 的结果中提取 gene：
        优先 program["metadata"]["gene"]，fallback 到 program["code"] JSON 中的 "_gene"/"gene"。
        """
        if not isinstance(program, dict):
            return None
        md = program.get("metadata") or {}
        if isinstance(md, dict) and isinstance(md.get("gene"), list):
            g = [it for it in md.get("gene") if isinstance(it, dict)]
            return g if g else None
        code = program.get("code", "")
        obj = self._try_load_json(code) if isinstance(code, str) else None
        if isinstance(obj, dict):
            g2 = obj.get("_gene") or obj.get("gene") or obj.get("_history_gene")
            if isinstance(g2, list):
                g2 = [it for it in g2 if isinstance(it, dict)]
                return g2 if g2 else None
        return None
    def _gene_last_parameters(self, gene: List[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
        if not isinstance(gene, list) or not gene:
            return None
        for it in reversed(gene):
            if isinstance(it, dict) and isinstance(it.get("parameters"), dict):
                return it["parameters"]
        return None
    def _gene_to_prompt_text(self, gene: List[Dict[str, Any]], max_turns: int = 8) -> str:
        """
        把 gene 渲染成 prompt 可读文本，用于替换原 program_snippet(code)。
        默认展示最后 max_turns 条，避免过长。
        """
        if not isinstance(gene, list) or not gene:
            return ""
        items = [it for it in gene if isinstance(it, dict)]
        if not items:
            return ""
        tail = items[-max_turns:]
        lines: List[str] = []
        lines.append(f"<GeneTrajectory turns={len(gene)} show_last={len(tail)}>")
        for it in tail:
            turn = it.get("turn")
            score = it.get("score")
            params = it.get("parameters") if isinstance(it.get("parameters"), dict) else None
            perf = it.get("performance") if isinstance(it.get("performance"), dict) else None
            lines.append(f"- turn: {turn}  score: {score}")
            if params is not None:
                lines.append("  parameters: " + json.dumps(params, ensure_ascii=False))
            if perf is not None:
                lines.append("  performance: " + json.dumps(perf, ensure_ascii=False))
        lines.append("</GeneTrajectory>")
        return "\n".join(lines)
    def _program_snippet_for_prompt(self, program: Dict[str, Any], language: str) -> str:
        """
        统一生成用于 prompt 展示的 program_snippet：
        - 有 gene：展示 gene 轨迹（替换原 code）
        - 无 gene：展示原 code（json task 时 pretty）
        """
        gene = self._extract_gene_from_program_dict(program)
        if gene:
            return self._gene_to_prompt_text(gene)
        program_code = program.get("code", "") or ""
        is_json_task = (language or "").lower() == "json"
        if is_json_task:
            program_code = self._pretty_json(program_code)
        return program_code
    # ----------------------------- state preview helpers -----------------------------
    def _json_vars_preview(self, program_text: str, max_items: int = 10) -> str:
        """
        Build a short preview line from a JSON state/program string.
        Priorities:
          1) If contains gene: show gene turns + last parameters preview
          2) Else if contains variables dict: show variable count + sample pairs
        """
        obj = self._try_load_json(program_text) if isinstance(program_text, str) else None
        if not isinstance(obj, dict):
            return ""
        # ✅ 优先：gene 轨迹摘要（适用于 current_program / parent_program state json）
        gene = obj.get("gene")
        if isinstance(gene, list) and gene:
            gene_items = [it for it in gene if isinstance(it, dict)]
            last_params = self._gene_last_parameters(gene_items)
            if isinstance(last_params, dict):
                keys = list(last_params.keys())
                preview_k = keys[: min(max_items, len(keys))]
                pairs = []
                for k in preview_k:
                    v = last_params.get(k)
                    if isinstance(v, (str, int, float)):
                        pairs.append(f"{k}={v}")
                suffix = "..." if len(keys) > len(preview_k) else ""
                return f"gene轨迹：turns={len(gene)}；最后一轮参数示例：{', '.join(pairs)}{suffix}"
            return f"gene轨迹：turns={len(gene)}"
        # fallback：variables dict
        vars_dict = obj.get("variables")
        if not isinstance(vars_dict, dict):
            return ""
        keys = list(vars_dict.keys())
        preview_k = keys[: min(max_items, len(keys))]
        pairs = []
        for k in preview_k:
            v = vars_dict.get(k)
            if isinstance(v, (str, int, float)):
                pairs.append(f"{k}={v}")
        suffix = "..." if len(keys) > len(preview_k) else ""
        return f"参数数量：{len(keys)}；示例：{', '.join(pairs)}{suffix}"
    def _maybe_shorten_state_json(self, text: str, title: str) -> str:
        """
        Keep prompts close to desired format:
        - Default: NOT dump huge state JSON blocks
        - But allow keeping full JSON if env OPENEOLVE_KEEP_STATE_JSON=1
        """
        keep_full = os.getenv("OPENEOLVE_KEEP_STATE_JSON", "1") in ("1", "true", "True", "yes", "YES")
        if keep_full:
            return self._pretty_json(text) if isinstance(text, str) else (text or "")
        preview = self._json_vars_preview(text)
        if preview:
            return f"{title}：{preview}"
        if isinstance(text, str) and text.strip():
            s = text.strip().replace("\n", " ")
            if len(s) > 200:
                s = s[:200] + "..."
            return f"{title}：{s}"
        return ""
    # ----------------------------- prompt build -----------------------------
    def build_prompt(
        self,
        current_program: str = "",
        parent_program: str = "",
        initial_program: str = "",
        program_metrics: Optional[Dict[str, float]] = None,
        previous_programs: Optional[List[Dict[str, Any]]] = None,
        top_programs: Optional[List[Dict[str, Any]]] = None,
        inspirations: Optional[List[Dict[str, Any]]] = None,
        language: str = "python",
        evolution_round: int = 0,
        diff_based_evolution: bool = True,
        template_key: Optional[str] = None,
        program_artifacts: Optional[Dict[str, Union[str, bytes]]] = None,
        feature_dimensions: Optional[List[str]] = None,
        **kwargs: Any,
    ) -> Dict[str, str]:
        program_metrics = program_metrics or {}
